actions.script:
import org.moqui.agent.AgentConfigUtil
def ef = ec.entity
if (!ef.isEntityDefined(entityName)) {
    ec.message.addError("Entity non definita: ${entityName}")
    return
}
Set<String> debugGroups = ['MCP_DEBUG', 'ADMIN'] as Set
Set<String> userGroups = (ec.user.userGroupIdSet ?: []) as Set<String>
boolean isPrivileged = !userGroups.intersect(debugGroups).isEmpty()
Set<String> sensitiveEntityNames = [
        'moqui.security.UserAccount',
        'mantle.party.Party',
        'mantle.account.invoice.Invoice',
        'mantle.order.OrderHeader',
        'mantle.account.payment.Payment',
        'mantle.account.financial.FinancialAccount'
] as Set<String>
Map<String, List<String>> safeFieldListByEntity = [
        'moqui.security.UserAccount' : ['userId', 'username', 'userFullName', 'disabled'],
        'mantle.party.Party' : ['partyId', 'partyTypeEnumId', 'statusId', 'description'],
        'mantle.account.invoice.Invoice' : ['invoiceId', 'invoiceTypeEnumId', 'partyId', 'fromPartyId', 'toPartyId', 'invoiceDate', 'statusId'],
        'mantle.order.OrderHeader' : ['orderId', 'orderTypeEnumId', 'orderDate', 'entryDate', 'statusId', 'partyId', 'customerPartyId'],
        'mantle.account.payment.Payment' : ['paymentId', 'paymentTypeEnumId', 'partyId', 'amount', 'statusId', 'effectiveDate'],
        'mantle.account.financial.FinancialAccount' : ['financialAccountId', 'financialAccountTypeEnumId', 'ownerPartyId', 'statusId']
]
if ((conditions == null || conditions.isEmpty()) && sensitiveEntityNames.contains(entityName) && !isPrivileged) {
    ec.message.addError("Query senza condizioni non consentita per entity sensibile: ${entityName}")
    return
}
def find = ef.find(entityName)

(conditions ?: [:]).each { k, v -> find.condition(k as String, v) }
if (orderBy) find.orderBy(orderBy as List<String>)
int maxLimit = AgentConfigUtil.getInt('moqui.agent.find.maxLimit', 100, 1)
limitUsed = Math.min((limit ?: 50) as Integer, maxLimit)
find.limit(limitUsed)

def rows = find.list()
List effectiveFieldList = (fieldList instanceof List && !fieldList.isEmpty()) ? (fieldList as List) : null
if (!effectiveFieldList && sensitiveEntityNames.contains(entityName) && !isPrivileged) {
    effectiveFieldList = safeFieldListByEntity[entityName]
}
if (effectiveFieldList) {
    recordList = rows.collect { ev ->
        def row = [:]
        effectiveFieldList.each { f -> row[f] = ev.get(f as String) }
        row
    }
} else {
    recordList = rows.collect { it.getMap() }
}

import org.moqui.agent.AgentConfigUtil
Map validation = AgentConfigUtil.validateRuntimeConfiguration(ec, [ requireEmbedding : requireEmbedding, requireReranker : requireReranker, checkIndexes : checkIndexes ]) status = validation.status errors = (validation.errors ?: []) as List warnings = (validation.warnings ?: []) as List details = (validation.details ?: [:]) as Map
if (Boolean.TRUE.equals(failOnError) && errors) { throw new IllegalStateException(errors.join('; ')) }

import org.moqui.agent.AgentToolSupport

Closure findSessionContext = { String lookupVisitId, String lookupSessionId ->
    def find = ec.entity.find('moqui.agent.AgentSessionContext')
            .condition('userId', ec.user.userId)
    if (lookupVisitId) {
        return find.condition('visitId', lookupVisitId).one()
    } else if (lookupSessionId) {
        return find.condition('sessionId', lookupSessionId).one()
    } else {
        return null
    }
}

String effectiveVisitId = visitId ?: sessionId ?: ec.user.visitId
String effectiveSessionId = sessionId ?: effectiveVisitId
def nowTs = ec.user.nowTimestamp
def asCtx = findSessionContext(effectiveVisitId, effectiveSessionId)

if (!asCtx && Boolean.TRUE.equals(createIfMissing) && effectiveVisitId) {
    def userAccount = ec.entity.find('moqui.security.UserAccount').condition('userId', ec.user.userId).useCache(true).one()
    asCtx = ec.entity.makeValue('moqui.agent.AgentSessionContext')
    asCtx.setSequencedIdPrimary()
    asCtx.setAll([
            visitId : effectiveVisitId,
            userId : ec.user.userId,
            partyId : userAccount?.partyId,
            sessionId : effectiveSessionId,
            contextStorageModeEnumId : 'AgCtxExternalOnly',
            statusId : 'AgSessOpen',
            createdDate : nowTs,
            lastUpdatedDate : nowTs,
            lastActivityDate : nowTs
    ])
    try {
        asCtx.create()
    } catch (Throwable createFailure) {
        // Concurrent MCP requests can race on the unique visit/session indexes.
        // If another request created the row first, recover it and clear the transient entity errors.
        ec.message.clearErrors()
        for (int retry = 0; retry < 3 && !asCtx; retry++) {
            if (retry > 0) Thread.sleep(50L * retry)
            asCtx = findSessionContext(effectiveVisitId, effectiveSessionId)
        }
        if (!asCtx) throw createFailure
        asCtx.lastActivityDate = nowTs
        asCtx.lastUpdatedDate = nowTs
        asCtx.update()
    }
} else if (asCtx) {
    asCtx.lastActivityDate = nowTs
    if (effectiveSessionId && !asCtx.sessionId) asCtx.sessionId = effectiveSessionId
    asCtx.update()
}

if (asCtx) {
    agentSessionContext = asCtx.getMap()
    ['currentBusinessObjectsJson', 'loadedDocumentsJson', 'lastRetrievedDocumentsJson',
     'lastExecutedArtifactJson', 'lastResultJson'].each { String fieldName ->
        agentSessionContext[fieldName - 'Json'] = AgentToolSupport.fromJson(asCtx.getString(fieldName))
    }
}

import org.moqui.agent.AgentToolSupport

def asCtxMap = getSessionResult.agentSessionContext
if (!asCtxMap) throw new IllegalStateException('Impossibile inizializzare AgentSessionContext')
def asCtx = ec.entity.find('moqui.agent.AgentSessionContext')
        .condition('agentSessionContextId', asCtxMap.agentSessionContextId)
        .one()

if (currentArea != null) asCtx.currentArea = currentArea
if (currentSubArea != null) asCtx.currentSubArea = currentSubArea
if (currentScreen != null) asCtx.currentScreen = currentScreen
if (currentBusinessObjects != null) asCtx.currentBusinessObjectsJson = AgentToolSupport.toJson(currentBusinessObjects)
if (loadedDocuments != null) asCtx.loadedDocumentsJson = AgentToolSupport.toJson(loadedDocuments)
if (lastRetrievedDocuments != null) asCtx.lastRetrievedDocumentsJson = AgentToolSupport.toJson(lastRetrievedDocuments)
if (lastExecutedArtifact != null) asCtx.lastExecutedArtifactJson = AgentToolSupport.toJson(lastExecutedArtifact)
if (lastResult != null) asCtx.lastResultJson = AgentToolSupport.toJson(lastResult)
asCtx.lastUpdatedDate = ec.user.nowTimestamp
asCtx.lastActivityDate = ec.user.nowTimestamp
asCtx.update()

agentSessionContext = asCtx.getMap()
['currentBusinessObjectsJson', 'loadedDocumentsJson', 'lastRetrievedDocumentsJson',
 'lastExecutedArtifactJson', 'lastResultJson'].each { String fieldName ->
    agentSessionContext[fieldName - 'Json'] = AgentToolSupport.fromJson(asCtx.getString(fieldName))
}

import org.moqui.agent.AgentToolSupport
if (!ec.service.isServiceDefined(serviceName)) { throw new IllegalArgumentException("Service non definito: ${serviceName}") }
authzActionEnumId = AgentToolSupport.getServiceAuthzActionEnumId(serviceName) boolean allowed = AgentToolSupport.checkArtifactAccess(ec, 'AT_SERVICE', authzActionEnumId, serviceName) if (!allowed) { throw new org.moqui.context.ArtifactAuthorizationException("Accesso negato al servizio ${serviceName}") }
riskLevelEnumId = AgentToolSupport.determineRiskLevel(serviceName, null, null) boolean shouldLogDirectly = Boolean.TRUE.equals(directToolCall) || (toolName == 'moqui_call_service_guarded')
if (riskLevelEnumId == 'high' && !Boolean.TRUE.equals(confirmed)) { confirmationRequired = true serviceResult = [ success : false, confirmationRequired: true, riskLevel : riskLevelEnumId, serviceName : serviceName, authzActionEnumId : authzActionEnumId ] if (shouldLogDirectly) { ec.service.sync().name('org.moqui.agent.AgentExecutionServices.log#ToolExecution').parameters([ visitId : sessionId ?: ec.user.visitId, toolName : toolName ?: 'moqui_call_service_guarded', documentId : documentId, artifactTypeEnumId : 'AT_SERVICE', artifactName : serviceName, authzActionEnumId : authzActionEnumId, parameters : parameters ?: [:], result : serviceResult, success : false, confirmed : confirmed, riskLevelEnumId : riskLevelEnumId ]).call() } return }
boolean hadErrorsBeforeCall = ec.message.hasError() String errorsBeforeCall = hadErrorsBeforeCall ? ec.message.getErrorsString() : null serviceResult = ec.service.sync().name(serviceName).parameters(parameters ?: [:]).call() boolean hasErrorsAfterCall = ec.message.hasError() String errorsAfterCall = hasErrorsAfterCall ? ec.message.getErrorsString() : null if ((!hadErrorsBeforeCall && hasErrorsAfterCall) || (hadErrorsBeforeCall && errorsAfterCall && errorsAfterCall != errorsBeforeCall)) { throw new IllegalStateException("Service ${serviceName} returned errors: ${errorsAfterCall}") }
if (shouldLogDirectly) { ec.service.sync().name('org.moqui.agent.AgentExecutionServices.log#ToolExecution').parameters([ visitId : sessionId ?: ec.user.visitId, toolName : toolName ?: 'moqui_call_service_guarded', documentId : documentId, artifactTypeEnumId : 'AT_SERVICE', artifactName : serviceName, authzActionEnumId : authzActionEnumId, parameters : parameters ?: [:], result : serviceResult, success : true, confirmed : confirmed, riskLevelEnumId : riskLevelEnumId ]).call() }

messages = []
errors = []
executionPlan = org.moqui.agent.AgentToolSupport.inferStructuredPromptPlan(
        ec, queryText, (parameters instanceof Map ? (parameters as Map) : [:]))
success = Boolean.TRUE.equals(executionPlan?.planType)
if (!success) {
    errors.add("No structured execution plan inferred for query: ${queryText}")
} else if (executionPlan?.planningSource) {
    messages.add("Planning source: ${executionPlan.planningSource}")
}

messages = [] errors = []
Map directAssetCompositeResult = org.moqui.agent.AgentToolSupport.executeStructuredPromptPlan( ec, queryText, (parameters instanceof Map ? (parameters as Map) : [:]), confirmed, dryRun, sessionId ?: ec.user.visitId) if (directAssetCompositeResult?.compositeExecution) { resolvedDocumentId = 'agent-prompt://asset/assetdetail/updateasset' success = Boolean.TRUE.equals(directAssetCompositeResult.success) executionResult = directAssetCompositeResult.executionResult as Map if (directAssetCompositeResult.messages) messages.addAll(directAssetCompositeResult.messages as List) if (directAssetCompositeResult.errors) errors.addAll(directAssetCompositeResult.errors as List) return }
// Step 1: search for matching executable documents Map searchResult = ec.service.sync() .name('org.moqui.agent.AgentPromptServices.search#AgentPrompts') .parameters([ queryText : queryText, area : area, subArea : subArea, domainObject: domainObject, actionKind : actionKind, operationEffect: operationEffect, currentScreen: currentScreen, limit : Math.min(limit ?: 5, 10), includeNonExecutable: false ]).call()
List candidates = (searchResult?.resultList ?: []) as List candidateCount = candidates.size() as Integer
// Step 2: pick the top runtimeExecutable document Map topDoc = candidates.find { Map d -> Boolean.TRUE.equals(d.runtimeExecutable) } as Map if (!topDoc && candidates) topDoc = candidates.first() as Map
Map preferredAggregateRootDoc = org.moqui.agent.AgentToolSupport.selectPreferredAggregateRootDocument(queryText, candidates) if (preferredAggregateRootDoc) topDoc = preferredAggregateRootDoc if (!preferredAggregateRootDoc && org.moqui.agent.AgentToolSupport.looksLikeProjectAggregatePrompt(queryText)) { Map fallbackProjectRootDoc = ec.service.sync() .name('org.moqui.agent.AgentPromptServices.get#AgentDocument') .parameters([documentId : 'agent-prompt://project/findproject/createproject']) .call()?.document as Map if (Boolean.TRUE.equals(fallbackProjectRootDoc?.runtimeExecutable)) topDoc = fallbackProjectRootDoc } if (!preferredAggregateRootDoc && org.moqui.agent.AgentToolSupport.inferStructuredPromptPlan( ec, queryText, (parameters instanceof Map ? (parameters as Map) : [:]))?.planType) { Map fallbackAssetDoc = ec.service.sync() .name('org.moqui.agent.AgentPromptServices.get#AgentDocument') .parameters([documentId : 'agent-prompt://asset/assetdetail/updateasset']) .call()?.document as Map if (Boolean.TRUE.equals(fallbackAssetDoc?.runtimeExecutable)) topDoc = fallbackAssetDoc }
if (!topDoc) { success = false errors.add("No agent document found for query: ${queryText}") return }
resolvedDocumentId = topDoc.documentId as String resolvedDocument = topDoc
if (!Boolean.TRUE.equals(topDoc.runtimeExecutable)) { success = false errors.add("Top document ${resolvedDocumentId} is not executable. Inspect it with moqui_get_agent_document.") return }
Map inferredParameters = org.moqui.agent.AgentToolSupport.inferPromptParameters(queryText, topDoc) Map mergedParameters = [:] if (inferredParameters) mergedParameters.putAll(inferredParameters) if (parameters instanceof Map) mergedParameters.putAll(parameters as Map)
Map aggregateResult = org.moqui.agent.AgentToolSupport.executeProjectAggregatePlan( ec, queryText, topDoc, mergedParameters, confirmed, dryRun, sessionId ?: ec.user.visitId) if (aggregateResult?.compositeExecution) { success = Boolean.TRUE.equals(aggregateResult.success) executionResult = aggregateResult.executionResult as Map if (aggregateResult.messages) messages.addAll(aggregateResult.messages as List) if (aggregateResult.errors) errors.addAll(aggregateResult.errors as List) return }
// Step 3: execute Map execResult = ec.service.sync() .name('org.moqui.agent.AgentExecutionServices.execute#AgentPrompt') .parameters([ documentId : resolvedDocumentId, parameters : mergedParameters, confirmed : confirmed, dryRun : dryRun, useSessionContext : true, sessionId : sessionId ?: ec.user.visitId ]).call()
success = Boolean.TRUE.equals(execResult?.success) executionResult = execResult if (execResult?.messages) messages.addAll(execResult.messages as List) if (execResult?.errors) errors.addAll(execResult.errors as List)

import java.sql.Timestamp
int days = Math.max(1, retainDays ?: 30) long cutoffMs = System.currentTimeMillis() - (days * 86400000L) Timestamp cutoff = new Timestamp(cutoffMs)
def toDelete = ec.entity.find('moqui.agent.AgentSessionContext') .condition('lastUpdatedDate', org.moqui.entity.EntityCondition.ComparisonOperator.LESS_THAN, cutoff) .list()
deletedCount = toDelete.size() if (deletedCount > 0) { toDelete*.delete() ec.logger.info("purge#OldAgentSessionContexts: deleted ${deletedCount} contexts older than ${days} days (cutoff ${cutoff})") }

String userId = ec.user.userId def nowTs = ec.user.nowTimestamp def userAccount = ec.entity.find('moqui.security.UserAccount').condition('userId', userId).useCache(true).one()
// Update existing session if clientTypeEnumId + clientSessionId + userId already present def existing = (clientTypeEnumId && clientSessionId) ? ec.entity.find('moqui.agent.AgentSessionContext') .condition('clientTypeEnumId', clientTypeEnumId) .condition('clientSessionId', clientSessionId) .condition('userId', userId) .one() : null
if (existing) { existing.setAll([ clientBaseUrl : clientBaseUrl, clientContextId : clientContextId, clientConversationId : clientConversationId, clientUrl : clientUrl, providerEnumId : providerEnumId, providerSessionId : providerSessionId, providerConversationId : providerConversationId, providerThreadId : providerThreadId, providerLastResponseId : providerLastResponseId, modelName : modelName, contextStorageModeEnumId : contextStorageModeEnumId ?: 'AgCtxExternalOnly', statusId : 'AgSessOpen', lastUpdatedDate : nowTs, lastActivityDate : nowTs, partyId : existing.partyId ?: userAccount?.partyId ]) existing.update() agentSessionContextId = existing.agentSessionContextId agentSessionId = existing.agentSessionContextId agentSessionContext = existing.getMap() return }
def sess = ec.entity.makeValue('moqui.agent.AgentSessionContext') sess.setSequencedIdPrimary() sess.setAll([ userId : userId, partyId : userAccount?.partyId, clientTypeEnumId : clientTypeEnumId, clientBaseUrl : clientBaseUrl, clientSessionId : clientSessionId, clientContextId : clientContextId, clientConversationId : clientConversationId, clientUrl : clientUrl, providerEnumId : providerEnumId, providerSessionId : providerSessionId, providerConversationId : providerConversationId, providerThreadId : providerThreadId, providerLastResponseId : providerLastResponseId, modelName : modelName, contextStorageModeEnumId : contextStorageModeEnumId ?: 'AgCtxExternalOnly', statusId : 'AgSessOpen', createdDate : nowTs, lastUpdatedDate : nowTs, lastActivityDate : nowTs ]) sess.create() agentSessionContextId = sess.agentSessionContextId agentSessionId = sess.agentSessionContextId agentSessionContext = sess.getMap()

import org.moqui.agent.AgentConfigUtil
String userId = ec.user.userId
Set userGroups = (ec.user.userGroupIdSet ?: []) as Set
boolean isPrivileged = userGroups.contains('ADMIN') || userGroups.contains('MCP_DEBUG')

def find = ec.entity.find('moqui.agent.AgentSessionContext')
if (!isPrivileged) find.condition('userId', userId)
if (statusId) find.condition('statusId', statusId)
if (clientTypeEnumId) find.condition('clientTypeEnumId', clientTypeEnumId)
int maxLimit = AgentConfigUtil.getInt('moqui.agent.find.maxLimit', 100, 1)
find.limit(Math.min(limit ?: 20, maxLimit))
find.orderBy(['-lastActivityDate', '-lastUpdatedDate'])
agentSessionList = find.list().collect { it.getMap() }
